import UIKit

class UniversalLinkHandler {
    static let shared = UniversalLinkHandler()
    
    private init() {}
    
    func handleUniversalLink(_ url: URL) -> Bool {
        guard let host = url.host else { return false }
        
        let pathComponents = url.pathComponents.filter { !$0.isEmpty }
        
        switch pathComponents.count {
        case 2 where pathComponents[0] == "profile":
            handleProfileLink(userId: pathComponents[1])
            return true
            
        case 2 where pathComponents[0] == "payment":
            handlePaymentLink(action: pathComponents[1])
            return true
            
        case 3 where pathComponents[0] == "admin":
            handleAdminLink(section: pathComponents[1], subSection: pathComponents[2])
            return true
            
        default:
            return false
        }
    }
    
    private func handleProfileLink(userId: String) {
        DispatchQueue.main.async {
            if let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
               let window = windowScene.windows.first {
                let storyboard = UIStoryboard(name: "Main", bundle: nil)
                if let profileVC = storyboard.instantiateViewController(withIdentifier: "ProfileViewController") as? ProfileViewController {
                    profileVC.userId = userId
                    window.rootViewController?.pushViewController(profileVC, animated: true)
                }
            }
        }
    }
    
